const assets = {"/index.html":{"body":"﻿<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>MPD 360 Pill Calculator</title>\n    <meta\n      name=\"description\"\n      content=\"MPD pill calculations and automatically trimmed pumping schedules with No Slug and With Slug modes.\"\n    />\n    <meta name=\"theme-color\" content=\"#111827\" />\n    <meta property=\"og:title\" content=\"MPD 360 Pill Calculator\" />\n    <meta\n      property=\"og:description\"\n      content=\"Build and export No Slug or With Slug MPD pill schedules with automatic pressure calculations.\"\n    />\n    <meta property=\"og:type\" content=\"website\" />\n    <meta property=\"og:image\" content=\"og.png\" />\n    <meta name=\"twitter:card\" content=\"summary_large_image\" />\n    <link rel=\"stylesheet\" href=\"styles.css\" />\n  </head>\n  <body>\n    <header class=\"app-header\">\n      <div>\n        <p class=\"eyebrow\">Stasis Drilling</p>\n        <h1>MPD 360 Pill Calculator</h1>\n      </div>\n      <div class=\"header-actions\">\n        <button type=\"button\" class=\"ghost-button\" id=\"loadExample\">Load Example</button>\n        <button type=\"button\" class=\"ghost-button\" id=\"saveScenario\">Save Scenario</button>\n        <button type=\"button\" class=\"ghost-button\" id=\"loadScenario\">Load Saved</button>\n        <button type=\"button\" class=\"ghost-button\" id=\"exportSchedule\">Export CSV</button>\n        <button type=\"button\" class=\"ghost-button\" id=\"resetInputs\">Reset</button>\n        <button type=\"button\" class=\"primary-button\" id=\"printReport\">Print</button>\n      </div>\n    </header>\n\n    <main class=\"app-shell\">\n      <aside class=\"input-panel\" aria-label=\"Engineering inputs\">\n        <div class=\"panel-title\">\n          <h2>Inputs</h2>\n          <span id=\"validityPill\">Waiting for values</span>\n        </div>\n        <div id=\"inputSections\"></div>\n      </aside>\n\n      <section class=\"workspace\">\n        <nav class=\"tabs\" aria-label=\"Calculator views\">\n          <button class=\"tab active\" type=\"button\" data-tab=\"summary\">Summary</button>\n          <button class=\"tab\" type=\"button\" data-tab=\"schedule\">Schedule</button>\n          <button class=\"tab\" type=\"button\" data-tab=\"schematic\">Schematic</button>\n          <button class=\"tab\" type=\"button\" data-tab=\"cement\">Cement</button>\n          <button class=\"tab\" type=\"button\" data-tab=\"audit\">Audit</button>\n          <div class=\"pill-mode-switch\" role=\"radiogroup\" aria-label=\"Pill mode\">\n            <span class=\"mode-switch-label\">Mode</span>\n            <label class=\"mode-option\">\n              <input type=\"radio\" name=\"pillMode\" value=\"noSlug\" checked />\n              <span>No Slug</span>\n            </label>\n            <label class=\"mode-option\">\n              <input type=\"radio\" name=\"pillMode\" value=\"withSlug\" />\n              <span>With Slug</span>\n            </label>\n          </div>\n        </nav>\n\n        <section class=\"tab-panel active\" id=\"summary\">\n          <section class=\"job-strip\" aria-label=\"Current scenario\">\n            <div>\n              <span>Well</span>\n              <strong id=\"jobWell\">-</strong>\n            </div>\n            <div>\n              <span>Client</span>\n              <strong id=\"jobClient\">-</strong>\n            </div>\n            <div>\n              <span>Date</span>\n              <strong id=\"jobDate\">-</strong>\n            </div>\n            <div>\n              <span>Section</span>\n              <strong id=\"jobSection\">-</strong>\n            </div>\n          </section>\n          <div class=\"kpi-grid\" id=\"kpiGrid\"></div>\n          <div class=\"split-layout\" id=\"summarySplit\">\n            <section class=\"data-section\" id=\"pillSection\">\n              <div class=\"section-heading\">\n                <h2>Pill Calculations</h2>\n              </div>\n              <div class=\"metric-list\" id=\"pillMetrics\"></div>\n            </section>\n            <section class=\"data-section\" id=\"slugSection\">\n              <div class=\"section-heading\">\n                <h2>Slug Calculations</h2>\n              </div>\n              <div class=\"metric-list\" id=\"slugMetrics\"></div>\n            </section>\n          </div>\n          <section class=\"data-section procedure-results\">\n            <div class=\"section-heading\">\n              <h2>Procedure Results</h2>\n            </div>\n            <div class=\"procedure-results-body\">\n              <p class=\"procedure-outcome\" id=\"procedureOutcome\"></p>\n              <div class=\"procedure-result-grid\">\n                <div class=\"procedure-result-group\">\n                  <h3>Pill Placement</h3>\n                  <div id=\"placementResults\"></div>\n                </div>\n                <div class=\"procedure-result-group\">\n                  <h3>Balanced Pill w/ DP ESD</h3>\n                  <div id=\"withDpResults\"></div>\n                </div>\n                <div class=\"procedure-result-group\">\n                  <h3>Balanced Pill w/o DP ESD</h3>\n                  <div id=\"withoutDpResults\"></div>\n                </div>\n              </div>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"tab-panel\" id=\"schedule\">\n          <section class=\"pressure-summary\" aria-label=\"Calculated schedule outputs\">\n            <div>\n              <span>Static Stripping Pressure</span>\n              <strong id=\"scheduleStaticPressure\">Pending</strong>\n              <small>psi</small>\n            </div>\n            <div>\n              <span>MAX Dynamic SBP</span>\n              <strong id=\"scheduleMaxDynamic\">Pending</strong>\n              <small>psi</small>\n            </div>\n            <div>\n              <span>Final Pump Volume</span>\n              <strong id=\"scheduleFinalVolume\">Pending</strong>\n              <small>bbls</small>\n            </div>\n            <div>\n              <span>Final Total Strokes</span>\n              <strong id=\"scheduleFinalStrokes\">Pending</strong>\n              <small>stks</small>\n            </div>\n          </section>\n          <section class=\"data-section\">\n            <div class=\"section-heading\">\n              <h2>Trip Speed Pressure Table</h2>\n              <span class=\"section-badge\" id=\"tripTableLabel\">Auto</span>\n            </div>\n            <div class=\"table-wrap\">\n              <table>\n                <thead>\n                  <tr>\n                    <th>Trip speed</th>\n                    <th>Swab AP</th>\n                    <th>Swab AP</th>\n                    <th>Dynamic pressure</th>\n                  </tr>\n                </thead>\n                <tbody id=\"tripSpeedRows\"></tbody>\n              </table>\n            </div>\n          </section>\n          <section class=\"data-section\">\n            <div class=\"section-heading\">\n              <h2 id=\"scheduleTitle\">Standard Pill - No Slug</h2>\n              <div class=\"schedule-controls\">\n                <span id=\"scheduleMode\">Waiting for inputs</span>\n                <label class=\"toggle-control\">\n                  <input type=\"checkbox\" id=\"showCutoff\" />\n                  <span>Show cutoff row</span>\n                </label>\n              </div>\n            </div>\n            <div class=\"table-wrap\">\n              <table class=\"schedule-table\">\n                <thead>\n                  <tr>\n                    <th>Step</th>\n                    <th>SBP<br />(psi)</th>\n                    <th>Flow Rate<br />(gpm)</th>\n                    <th>Volume<br />(bbls)</th>\n                    <th>Total Strokes<br />(stks)</th>\n                    <th>Density In<br />(ppg)</th>\n                    <th>Static SBP<br />(psi)</th>\n                    <th>Activity Notes</th>\n                  </tr>\n                </thead>\n                <tbody id=\"scheduleRows\"></tbody>\n              </table>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"tab-panel\" id=\"schematic\">\n          <section class=\"data-section schematic-section\">\n            <div class=\"section-heading\">\n              <h2>Wellbore Schematic</h2>\n              <span class=\"section-badge\" id=\"schematicMode\">No Slug</span>\n            </div>\n            <div class=\"schematic-body\">\n              <div class=\"schematic-legend\" aria-label=\"Schematic legend\">\n                <span><i class=\"legend-swatch annular-pill\"></i>Annular KMW</span>\n                <span>\n                  <i class=\"legend-swatch pipe-pill\"></i>\n                  <span id=\"drillStringLegend\">KMW in drill string</span>\n                </span>\n                <span><i class=\"legend-line solid\"></i>Calculated depth</span>\n                <span><i class=\"legend-line dashed\"></i>No-DP comparison</span>\n              </div>\n              <div class=\"schematic-canvas-wrap\">\n                <canvas\n                  id=\"wellboreCanvas\"\n                  class=\"schematic-canvas\"\n                  width=\"1100\"\n                  height=\"640\"\n                  role=\"img\"\n                  aria-label=\"Wellbore schematic pending calculated inputs\"\n                >\n                  Live wellbore schematic showing pill placement and calculated depths.\n                </canvas>\n              </div>\n            </div>\n          </section>\n        </section>\n\n        <section class=\"tab-panel\" id=\"cement\">\n          <div class=\"kpi-grid compact\" id=\"cementGrid\"></div>\n          <section class=\"data-section\">\n            <div class=\"section-heading\">\n              <h2>Offline Cement Pill</h2>\n            </div>\n            <div class=\"metric-list\" id=\"cementMetrics\"></div>\n          </section>\n        </section>\n\n        <section class=\"tab-panel\" id=\"audit\">\n          <section class=\"data-section\">\n            <div class=\"section-heading\">\n              <h2>Saved Scenario</h2>\n              <span id=\"saveStatus\">Not saved this session</span>\n            </div>\n            <div class=\"metric-list\" id=\"scenarioMetrics\"></div>\n          </section>\n          <section class=\"data-section\">\n            <div class=\"section-heading\">\n              <h2>Validation</h2>\n            </div>\n            <div id=\"warnings\" class=\"warnings\"></div>\n          </section>\n          <section class=\"data-section\">\n            <div class=\"section-heading\">\n              <h2>Calculation Notes</h2>\n            </div>\n            <p class=\"note\">\n              This app ports the primary formulas from the workbook's Inputs and standard pill\n              sheets, including the separate No Slug and With Slug schedules. Spreadsheet errors\n              remain pending until the required inputs are present.\n            </p>\n          </section>\n        </section>\n      </section>\n    </main>\n\n    <script src=\"app.js\"></script>\n  </body>\n</html>\n\r\n","contentType":"text/html; charset=utf-8","encoding":"text"},"/app.js":{"body":"﻿const inputSections = [\n  {\n    title: \"Well Information\",\n    fields: [\n      [\"wellName\", \"Well name\", \"\", \"text\"],\n      [\"client\", \"Client\", \"\", \"text\"],\n      [\"date\", \"Date\", \"\", \"date\"],\n      [\"producedBy\", \"Produced by\", \"\", \"text\"],\n    ],\n  },\n  {\n    title: \"Geometry\",\n    fields: [\n      [\"currentDepthMd\", \"Current well depth (MD)\", \"ft\"],\n      [\"anchorMd\", \"Anchor point / BOC (MD)\", \"ft\"],\n      [\"anchorTvd\", \"Anchor point / BOC (TVD)\", \"ft\"],\n      [\"casingMd\", \"Casing depth (MD)\", \"ft\"],\n      [\"casingTvd\", \"Casing depth (TVD)\", \"ft\"],\n      [\"spotMd\", \"Spot depth (MD)\", \"ft\"],\n      [\"spotTvd\", \"Spot depth (TVD)\", \"ft\"],\n      [\"openHoleDia\", \"Open hole diameter\", \"in\"],\n      [\"odDp\", \"OD drill pipe\", \"in\"],\n      [\"idDp\", \"ID drill pipe\", \"in\"],\n      [\"idCasing\", \"ID casing\", \"in\"],\n    ],\n  },\n  {\n    title: \"Fluid and Pressure\",\n    fields: [\n      [\"desiredEmw\", \"Desired EMW at anchor point\", \"ppge\"],\n      [\"currentMw\", \"Current MW\", \"ppg\"],\n      [\"kmw\", \"KMW\", \"ppg\"],\n      [\"pumpDisp\", \"Pump displacement\", \"bbl/stk\"],\n      [\"sbpConnection\", \"SBP on connection\", \"psi\"],\n      [\"fit\", \"FIT\", \"ppge\"],\n      [\"maxFlowRate\", \"Max flow rate\", \"gpm\"],\n    ],\n  },\n  {\n    title: \"Operational Settings\",\n    fields: [\n      [\"desiredResolution\", \"Desired resolution\", \"bbl\"],\n      [\"initialFlowRate\", \"Initial flow rate\", \"gpm\"],\n      [\"staticStrippingPressure\", \"Static stripping pressure\", \"psi\", \"output\"],\n      [\"maxDynamicSbp\", \"Max dynamic SBP\", \"psi\", \"output\"],\n      [\"overbalanceSlug\", \"Over balance pressure for slug\", \"psi\"],\n      [\"safevisionNoSlug\", \"Safevision AP ECD, no slug\", \"ppge\"],\n      [\"safevisionSlug\", \"Safevision AP ECD, with slug\", \"ppge\"],\n      [\"sectionType\", \"Section type\", \"\", \"select\", [\"Production\", \"Intermediate\"]],\n    ],\n  },\n  {\n    title: \"Offline Cement Pill\",\n    fields: [\n      [\"cementDesiredEsd\", \"Desired ESD\", \"ppge\"],\n      [\"newCasingOd\", \"New casing OD\", \"in\"],\n      [\"newCasingId\", \"New casing ID\", \"in\"],\n      [\"cementMw\", \"MW\", \"ppg\"],\n      [\"tdDepth\", \"TD depth\", \"ft\"],\n    ],\n  },\n];\n\nconst slugOnlyFields = new Set([\"overbalanceSlug\", \"safevisionSlug\"]);\n\nconst defaults = {\n  pillMode: \"noSlug\",\n  wellName: \"\",\n  client: \"\",\n  date: new Date().toISOString().slice(0, 10),\n  producedBy: \"\",\n  sectionType: \"Production\",\n  currentDepthMd: \"\",\n  anchorMd: \"\",\n  anchorTvd: \"\",\n  casingMd: \"\",\n  casingTvd: \"\",\n  spotMd: \"\",\n  spotTvd: \"\",\n  openHoleDia: \"\",\n  desiredEmw: \"\",\n  odDp: \"\",\n  idDp: \"\",\n  idCasing: \"\",\n  currentMw: \"\",\n  pumpDisp: \"\",\n  kmw: \"\",\n  sbpConnection: \"\",\n  fit: \"\",\n  maxFlowRate: \"\",\n  desiredResolution: \"\",\n  initialFlowRate: \"\",\n  overbalanceSlug: \"\",\n  safevisionNoSlug: \"\",\n  safevisionSlug: \"\",\n  cementDesiredEsd: \"\",\n  newCasingOd: \"\",\n  newCasingId: \"\",\n  cementMw: \"\",\n  tdDepth: \"\",\n};\n\nconst example = {\n  wellName: \"RIG - WELL\",\n  client: \"Client\",\n  producedBy: \"Engineering\",\n  currentDepthMd: 17650,\n  anchorMd: 13900,\n  anchorTvd: 11250,\n  casingMd: 10450,\n  casingTvd: 10125,\n  spotMd: 15400,\n  spotTvd: 11120,\n  openHoleDia: 8.5,\n  desiredEmw: 13.9,\n  odDp: 5,\n  idDp: 4.276,\n  idCasing: 8.681,\n  currentMw: 12.4,\n  pumpDisp: 0.095,\n  kmw: 15.8,\n  sbpConnection: 320,\n  fit: 15.6,\n  maxFlowRate: 300,\n  desiredResolution: 25,\n  initialFlowRate: 180,\n  overbalanceSlug: 100,\n  safevisionNoSlug: 12.85,\n  safevisionSlug: 13.1,\n  sectionType: \"Production\",\n  cementDesiredEsd: 14.2,\n  newCasingOd: 7,\n  newCasingId: 6.276,\n  cementMw: 12.4,\n  tdDepth: 17650,\n};\n\nconst tripTables = {\n  \"6.75\": [\n    [40, 0.16],\n    [80, 0.26],\n    [100, 0.34],\n    [150, 0.49],\n    [200, 0.6],\n    [250, 0.64],\n    [300, 0.69],\n  ],\n  \"7.875\": [\n    [40, 0.12],\n    [80, 0.19],\n    [100, 0.26],\n    [150, 0.41],\n    [200, 0.47],\n    [250, 0.53],\n    [300, 0.6],\n  ],\n  \"8.5\": [\n    [40, 0.07],\n    [80, 0.12],\n    [100, 0.18],\n    [150, 0.25],\n    [200, 0.33],\n    [250, 0.39],\n    [300, 0.46],\n  ],\n  other: [\n    [40, 0.05],\n    [80, 0.1],\n    [100, 0.16],\n    [150, 0.23],\n    [200, 0.31],\n    [250, 0.37],\n    [300, 0.44],\n  ],\n};\n\nconst state = { ...defaults };\r\nconst storageKey = \"mpd360.savedScenario.v2\";\r\nlet scheduleCache = [];\nlet scheduleCutoffRow = null;\nlet scheduleMeta = { mode: \"noSlug\", finalVolume: NaN };\nlet schematicResizeFrame = null;\n\nconst byId = (id) => document.getElementById(id);\nconst isNum = (value) => Number.isFinite(value);\nconst n = (key) => {\n  if (state[key] === \"\" || state[key] === null || state[key] === undefined) return NaN;\n  const value = Number(state[key]);\n  return Number.isFinite(value) ? value : NaN;\n};\nconst safeDiv = (a, b) => (isNum(a) && isNum(b) && Math.abs(b) > 1e-9 ? a / b : NaN);\nconst round = (v, digits = 0) =>\n  isNum(v) ? Number(v.toFixed(Math.max(0, digits))) : NaN;\nconst roundup = (v, digits = 0) => {\n  if (!isNum(v)) return NaN;\n  const factor = 10 ** digits;\n  return Math.ceil(v * factor) / factor;\n};\nconst floorTo = (v, step) => (isNum(v) ? Math.floor(v / step) * step : NaN);\nconst ceilMath = (v, significance = 1) =>\r\n  isNum(v) && significance ? Math.ceil(v / significance) * significance : NaN;\r\nconst nonNegative = (value) => (isNum(value) ? Math.max(0, value) : NaN);\r\nconst textOrDash = (value) =>\r\n  value === \"\" || value === null || value === undefined ? \"-\" : value;\n\nfunction fmt(value, unit = \"\", digits = 1) {\n  if (!isNum(value)) return `<span class=\"pending\">Pending</span>`;\n  const rounded = Math.abs(value) >= 100 ? round(value, 0) : round(value, digits);\n  return `${rounded.toLocaleString(undefined, {\n    maximumFractionDigits: digits,\n  })}${unit ? ` ${unit}` : \"\"}`;\n}\n\nfunction numberText(value, digits = 0) {\n  if (!isNum(value)) return \"Pending\";\n  return value.toLocaleString(undefined, {\n    minimumFractionDigits: digits,\n    maximumFractionDigits: digits,\n  });\n}\n\nfunction tripTableKey(diameter) {\n  if (Math.abs(diameter - 6.75) < 0.001) return \"6.75\";\n  if (Math.abs(diameter - 7.875) < 0.001) return \"7.875\";\n  if (Math.abs(diameter - 8.5) < 0.001) return \"8.5\";\n  return \"other\";\n}\n\nfunction inputValue(key) {\n  return state[key] ?? \"\";\n}\n\nfunction buildInputs() {\n  const root = byId(\"inputSections\");\n  root.innerHTML = inputSections\n    .map(\n      (section) => `\n        <section class=\"input-section\">\n          <h3>${section.title}</h3>\n          <div class=\"field-grid\">\n            ${section.fields\n              .map(([key, label, unit, type = \"number\", options]) => {\n                const control =\n                  type === \"output\"\n                    ? `<output id=\"${key}\" class=\"field-output\" aria-live=\"polite\">Pending</output>`\n                    : type === \"select\"\n                    ? `<select id=\"${key}\" data-key=\"${key}\">\n                        ${options\n                          .map(\n                            (option) =>\n                              `<option value=\"${option}\" ${inputValue(key) === option ? \"selected\" : \"\"}>${option}</option>`,\n                          )\n                          .join(\"\")}\n                      </select>`\n                    : `<input id=\"${key}\" data-key=\"${key}\" type=\"${type}\" value=\"${inputValue(key)}\" ${type === \"number\" ? 'step=\"any\"' : \"\"} />`;\n                return `\n                  <div class=\"field\" data-field-key=\"${key}\" ${slugOnlyFields.has(key) ? 'data-mode-only=\"withSlug\"' : \"\"}>\n                    <label for=\"${key}\">\n                      <span>${label}</span>\n                      <span class=\"unit\">${unit}</span>\n                    </label>\n                    ${control}\n                  </div>\n                `;\n              })\n              .join(\"\")}\n          </div>\n        </section>\n      `,\n    )\n    .join(\"\");\n\n  root.querySelectorAll(\"[data-key]\").forEach((control) => {\n    control.addEventListener(\"input\", (event) => {\n      state[event.target.dataset.key] = event.target.value;\n      render();\n    });\n  });\n}\n\nfunction calc() {\n  const currentMw = n(\"currentMw\");\n  const kmw = n(\"kmw\");\n  const anchorTvd = n(\"anchorTvd\");\n  const casingTvd = n(\"casingTvd\");\n  const casingMd = n(\"casingMd\");\n  const spotMd = n(\"spotMd\");\n  const spotTvd = n(\"spotTvd\");\n  const idDp = n(\"idDp\");\n  const odDp = n(\"odDp\");\n  const idCasing = n(\"idCasing\");\n  const openHoleDia = n(\"openHoleDia\");\n  const desiredEmw = n(\"desiredEmw\");\n  const desiredResolution = n(\"desiredResolution\");\n  const pumpDisp = n(\"pumpDisp\");\n  const fit = n(\"fit\");\n  const overbalanceSlug = n(\"overbalanceSlug\");\n  const safevisionNoSlug = n(\"safevisionNoSlug\");\n  const safevisionSlug = n(\"safevisionSlug\");\n\n  const staticStrippingPressure = (desiredEmw - currentMw) * 0.052 * anchorTvd;\n  const selectedTripTable = tripTableKey(openHoleDia);\n  const tripPressures = (tripTables[selectedTripTable] ?? tripTables.other).map(\n    ([speed, ppge]) => {\n      const swabPressure = ceilMath(ppge * 0.052 * anchorTvd, 10);\n      return {\n        speed,\n        ppge,\n        swabPressure,\n        dynamicPressure: staticStrippingPressure + swabPressure,\n      };\n    },\n  );\n  const maxSwabPressure = tripPressures.at(-1)?.swabPressure;\n  const maxDynamicSbp = staticStrippingPressure + maxSwabPressure;\n  const pressureGradient = (kmw - currentMw) * 0.052;\n  const targetPressure = (desiredEmw - currentMw) * 0.052 * anchorTvd;\n  const masp = (fit - currentMw) * 0.052 * casingTvd;\n  const initialApl = (safevisionNoSlug - currentMw) * 0.052 * casingTvd;\n  const drillStringCap = idDp ** 2 / 1029.4;\n  const drillStringVolAtSpot = round(drillStringCap * spotMd, 0);\n  const casingCap = idCasing ** 2 / 1029.4;\n  const annularCap = (idCasing ** 2 - odDp ** 2) / 1029.4;\n  const annularBelowShoe =\n    spotMd <= casingMd ? 0 : (openHoleDia ** 2 - odDp ** 2) / 1029.4;\n  const drillStringOpenHole = spotMd <= casingMd ? 0 : spotMd - casingMd;\n  const openHoleCap = (openHoleDia ** 2 - odDp ** 2) / 1029.4;\n  const volumeBelowShoe = drillStringOpenHole * openHoleCap;\n  const casingVolAtSpot =\n    spotMd <= casingMd ? casingCap * spotMd : casingCap * casingMd - volumeBelowShoe;\n  const annularAtSpot =\n    spotMd <= casingMd\n      ? annularCap * spotMd\n      : annularCap * (spotMd - drillStringOpenHole) +\n        annularBelowShoe * drillStringOpenHole;\n  const heightPillNoDp = ceilMath(safeDiv(targetPressure, pressureGradient), 10);\n  const totalPillVol = roundup(heightPillNoDp * casingCap, 0);\n  const requiredVolAnnulus = heightPillNoDp * annularCap;\n  const calculatedChase =\n    drillStringCap * spotMd - (totalPillVol - requiredVolAnnulus);\n  const correctedChase = calculatedChase <= 0 ? 0 : calculatedChase;\n  const correctedPillVol = round(\n    correctedChase === 0 ? requiredVolAnnulus - calculatedChase : requiredVolAnnulus,\n    0,\n  );\n  const finalKwm = correctedChase === 0 ? drillStringVolAtSpot : totalPillVol - requiredVolAnnulus;\n  const minHeightWithDp =\n    safeDiv(totalPillVol, (idCasing ** 2 - odDp ** 2 + idDp ** 2) / 1029.4) +\n    safeDiv(volumeBelowShoe, (openHoleDia ** 2 - odDp ** 2 + idDp ** 2) / 1029.4);\n  const balancedAdditionalPsi = (minHeightWithDp - heightPillNoDp) * pressureGradient;\n  const addPpgCsg = safeDiv(balancedAdditionalPsi, 0.052 * casingTvd);\n  const addPpgTarget = safeDiv(balancedAdditionalPsi, 0.052 * anchorTvd);\n  const esdCasingNoDp =\n    spotMd <= casingMd\n      ? safeDiv(targetPressure, 0.052 * casingTvd) + currentMw\n      : ((heightPillNoDp - spotTvd + casingTvd) * (kmw - currentMw)) /\n          casingTvd +\n        currentMw;\n  const balancedEsdCasing = esdCasingNoDp + addPpgCsg;\n  const anchorPointEsd = desiredEmw + addPpgTarget;\n  const resolutionHeightGain = safeDiv(desiredResolution, annularCap);\n  const resolutionPressureGain = (kmw - currentMw) * resolutionHeightGain * 0.052;\n  const pressureDifferential = (desiredEmw - safevisionNoSlug) * 0.052 * anchorTvd;\n  const pressureDifferentialSlug = (desiredEmw - safevisionSlug) * 0.052 * anchorTvd;\n  const slugPressure = maxDynamicSbp + overbalanceSlug;\n  const slugPillVol = safeDiv(slugPressure, pressureGradient) * drillStringCap;\n  const strokesToPumpSlug = safeDiv(slugPillVol, pumpDisp);\n  const pillVolAtSpot = totalPillVol - slugPillVol;\n  const slugFits = drillStringVolAtSpot > slugPillVol;\n  const slugFallOut = slugFits ? 0 : slugPillVol - drillStringVolAtSpot;\n  const slugFallHeight = safeDiv(slugFallOut, casingCap);\n  const chaseWithSlug = pillVolAtSpot + correctedChase;\n  const slugPpgEquivalent = safeDiv(slugFallHeight * pressureGradient, 0.052 * anchorTvd);\n  const slugPsiEquivalent = slugPpgEquivalent * 0.052 * anchorTvd;\n  const slugApl = (safevisionSlug - currentMw) * 0.052 * anchorTvd;\n  const correctedSlugPill = correctedPillVol + slugFallOut;\n  const combinedPillCapacity =\n    (idCasing ** 2 - odDp ** 2 + idDp ** 2) / 1029.4;\n  const pillHeightPosition =\n    minHeightWithDp < spotMd && spotMd > heightPillNoDp\n      ? minHeightWithDp - spotMd\n      : 0;\n  const correctedTotalPillAtSpot =\n    totalPillVol - round(pillHeightPosition * combinedPillCapacity, 0);\n  const totalPillVolAtSpotNoSlug =\n    spotMd > minHeightWithDp ? totalPillVol : correctedTotalPillAtSpot;\n  const totalPillVolAtSpotWithSlug =\n    pillVolAtSpot < annularAtSpot ? totalPillVol : correctedTotalPillAtSpot;\n  const topOfPillWithDp =\n    isNum(spotMd) && isNum(minHeightWithDp)\n      ? spotMd > minHeightWithDp\n        ? spotMd - minHeightWithDp\n        : \"Surface\"\n      : NaN;\n  const topOfPillNoDp = spotMd - heightPillNoDp;\n  const drillStringPillHeight = safeDiv(finalKwm, drillStringCap);\n  const topOfPillInsideDp =\n    isNum(spotMd) && isNum(drillStringPillHeight)\n      ? Math.max(0, spotMd - drillStringPillHeight)\n      : NaN;\n  const kwmPlusChase = roundup(totalPillVol + correctedChase, 0);\n\n  const cement = calcCement();\n\n  return {\n    masp,\n    initialApl,\n    drillStringCap,\n    drillStringVolAtSpot,\n    casingCap,\n    casingVolAtSpot,\n    annularCap,\n    annularBelowShoe,\n    annularAtSpot,\n    openHoleCap,\n    heightPillNoDp,\n    totalPillVol,\n    drillStringOpenHole,\n    volumeBelowShoe,\n    requiredVolAnnulus,\n    correctedPillVol,\n    calculatedChase,\n    correctedChase,\n    finalKwm,\n    minHeightWithDp,\n    balancedAdditionalPsi,\n    addPpgCsg,\n    addPpgTarget,\n    balancedEsdCasing,\n    esdCasingNoDp,\n    anchorPointEsd,\n    resolutionHeightGain,\n    resolutionPressureGain,\n    pressureDifferential,\n    pressureDifferentialSlug,\n    staticStrippingPressure,\n    maxDynamicSbp,\n    maxSwabPressure,\n    selectedTripTable,\n    tripPressures,\n    slugPressure,\n    slugPillVol,\n    strokesToPumpSlug,\n    pillVolAtSpot,\n    slugFits,\n    slugFallOut,\n    slugFallHeight,\n    chaseWithSlug,\n    slugPpgEquivalent,\n    slugPsiEquivalent,\n    slugApl,\n    correctedSlugPill,\n    correctedTotalPillAtSpot,\n    totalPillVolAtSpotNoSlug,\n    totalPillVolAtSpotWithSlug,\n    topOfPillWithDp,\n    topOfPillNoDp,\n    drillStringPillHeight,\n    topOfPillInsideDp,\n    kwmPlusChase,\n    cement,\n  };\n}\n\nfunction calcCement() {\n  const desiredEsd = n(\"cementDesiredEsd\");\n  const newCasingOd = n(\"newCasingOd\");\n  const newCasingId = n(\"newCasingId\");\n  const cementMw = n(\"cementMw\");\n  const tdDepth = n(\"tdDepth\");\n  const anchorMd = n(\"anchorMd\");\n  const casingMd = n(\"casingMd\");\n  const idCasing = n(\"idCasing\");\n  const openHoleDia = n(\"openHoleDia\");\n  const currentMw = n(\"currentMw\");\n  const kmw = n(\"kmw\");\n  const casingTvd = n(\"casingTvd\");\n\n  const staticPressure = (desiredEsd - cementMw) * 0.052 * casingTvd;\n  const annularCapacity = (idCasing ** 2 - newCasingOd ** 2) / 1029.4;\n  const openHoleCapacity = (openHoleDia ** 2 - newCasingOd ** 2) / 1029.4;\n  const casingStringCapacity = newCasingId ** 2 / 1029.4;\n  const openHoleToBoc = tdDepth - anchorMd;\n  const bocToShoe = anchorMd - casingMd;\n  const requiredPillHeight = ceilMath(safeDiv(staticPressure, (kmw - cementMw) * 0.052), 10);\n  const requiredCementPillVol = roundup(requiredPillHeight * annularCapacity, 0);\n  const totalCasingStringVol = casingStringCapacity * tdDepth;\n  const chaseToTd = totalCasingStringVol - requiredCementPillVol;\n  const chaseExitCasing = requiredCementPillVol;\n  const chaseBocToShoe = openHoleToBoc * openHoleCapacity;\n  const chaseBocShoePlusPill = bocToShoe * openHoleCapacity + requiredCementPillVol;\n  const totalChase = chaseBocShoePlusPill + chaseBocToShoe + totalCasingStringVol;\n  const topOfPill = casingMd - requiredPillHeight;\n\n  return {\n    staticPressure,\n    annularCapacity,\n    openHoleCapacity,\n    casingStringCapacity,\n    openHoleToBoc,\n    bocToShoe,\n    requiredPillHeight,\n    requiredCementPillVol,\n    totalCasingStringVol,\n    chaseToTd,\n    chaseExitCasing,\n    chaseBocToShoe,\n    chaseBocShoePlusPill,\n    totalChase,\n    topOfPill,\n  };\n}\n\nfunction metricRow(name, value, unit, digits = 1) {\n  return `\n    <div class=\"metric-row\">\n      <div class=\"metric-name\">${name}</div>\n      <div class=\"metric-value\">${fmt(value, unit, digits)}</div>\n    </div>\n  `;\n}\n\nfunction modeLabel(mode = state.pillMode) {\n  return mode === \"withSlug\" ? \"With Slug\" : \"No Slug\";\n}\n\nfunction renderModeUi() {\n  const withSlug = state.pillMode === \"withSlug\";\n  document.body.dataset.pillMode = state.pillMode;\n  document.querySelectorAll('[data-mode-only=\"withSlug\"]').forEach((field) => {\n    field.hidden = !withSlug;\n  });\n  document.querySelectorAll('input[name=\"pillMode\"]').forEach((control) => {\n    control.checked = control.value === state.pillMode;\n  });\n  byId(\"slugSection\").hidden = !withSlug;\n  byId(\"summarySplit\").classList.toggle(\"single-mode\", !withSlug);\n  byId(\"scheduleTitle\").textContent = `Standard Pill - ${modeLabel()}`;\n}\n\nfunction renderJobStrip() {\n  byId(\"jobWell\").textContent = textOrDash(state.wellName);\n  byId(\"jobClient\").textContent = textOrDash(state.client);\n  byId(\"jobDate\").textContent = textOrDash(state.date);\n  byId(\"jobSection\").textContent = textOrDash(state.sectionType);\n}\n\nfunction renderDerivedOutputs(results) {\n  byId(\"staticStrippingPressure\").textContent = numberText(\n    results.staticStrippingPressure,\n    0,\n  );\n  byId(\"maxDynamicSbp\").textContent = numberText(results.maxDynamicSbp, 0);\n}\n\nfunction renderScenarioMetrics(results) {\n  const saved = localStorage.getItem(storageKey);\n  byId(\"scenarioMetrics\").innerHTML = [\n    [\"Well\", state.wellName || \"-\", \"\"],\n    [\"Client\", state.client || \"-\", \"\"],\n    [\"Produced by\", state.producedBy || \"-\", \"\"],\n    [\"Pill mode\", modeLabel(), \"\"],\n    [\"Workbook source\", \"MPD 360 (2026) - RIG - WELL\", \"\"],\n    [\"Last saved locally\", saved ? \"Available\" : \"None\", \"\"],\n  ]\n    .map(([name, value]) => `\n      <div class=\"metric-row\">\n        <div class=\"metric-name\">${name}</div>\n        <div class=\"metric-value\">${value}</div>\n      </div>\n    `)\n    .join(\"\");\n}\nfunction renderKpis(results) {\n  const kpis = state.pillMode === \"withSlug\"\n    ? [\n        [\"MASP\", results.masp, \"psi\", 0],\n        [\"Total Pill Volume\", results.totalPillVol, \"bbl\", 0],\n        [\"Slug Volume\", results.slugPillVol, \"bbl\", 1],\n        [\"Chase with Slug\", results.chaseWithSlug, \"bbl\", 0],\n      ]\n    : [\n        [\"MASP\", results.masp, \"psi\", 0],\n        [\"Total Pill Volume\", results.totalPillVol, \"bbl\", 0],\n        [\"Corrected Chase\", results.correctedChase, \"bbl\", 0],\n        [\"Anchor Point ESD\", results.anchorPointEsd, \"ppge\", 2],\n      ];\n  byId(\"kpiGrid\").innerHTML = kpis\n    .map(\n      ([label, value, unit, digits]) => `\n        <article class=\"kpi\">\n          <div class=\"label\">${label}</div>\n          <div class=\"value\">${fmt(value, \"\", digits)}</div>\n          <div class=\"unit-text\">${unit}</div>\n        </article>\n      `,\n    )\n    .join(\"\");\n}\n\nfunction renderMetrics(results) {\n  byId(\"pillMetrics\").innerHTML = [\n    [\"Initial flowrate annular friction\", results.initialApl, \"psi\", 0],\n    [\"Drill string capacity\", results.drillStringCap, \"bbl/ft\", 4],\n    [\"Drill string volume at spot depth\", results.drillStringVolAtSpot, \"bbl\", 0],\n    [\"Casing capacity\", results.casingCap, \"bbl/ft\", 4],\n    [\"Annular capacity\", results.annularCap, \"bbl/ft\", 4],\n    [\"Open hole capacity\", results.openHoleCap, \"bbl/ft\", 4],\n    [\"Height of pill without DP\", results.heightPillNoDp, \"ft\", 0],\n    [\"Required pill volume in annulus\", results.requiredVolAnnulus, \"bbl\", 0],\n    [\"Corrected pill volume in annulus\", results.correctedPillVol, \"bbl\", 0],\n    [\"Final KWM in drill string\", results.finalKwm, \"bbl\", 0],\n    [\"Minimum height of pill with DP\", results.minHeightWithDp, \"ft\", 0],\n    [\"Balanced case additional pressure\", results.balancedAdditionalPsi, \"psi\", 0],\n    [\"Balanced ESD at casing shoe\", results.balancedEsdCasing, \"ppge\", 2],\n    [\"Top of pill without DP\", results.topOfPillNoDp, \"ft\", 0],\n  ]\n    .map((row) => metricRow(...row))\n    .join(\"\");\n\n  byId(\"slugMetrics\").innerHTML = [\n    [\"Initial pressure differential\", results.pressureDifferential, \"psi\", 0],\n    [\"Slug pressure\", results.slugPressure, \"psi\", 0],\n    [\"Slug pill volume of KMW\", results.slugPillVol, \"bbl\", 1],\n    [\"Strokes to pump slug\", results.strokesToPumpSlug, \"stk\", 0],\n    [\"Pill volume to pump at spot depth\", results.pillVolAtSpot, \"bbl\", 0],\n    [\"Capacity vs. slug logic check\", results.slugFits ? 0 : -1, \"\", 0],\n    [\"Slug fall out\", results.slugFallOut, \"bbl\", 1],\n    [\"Height equivalent of slug fall\", results.slugFallHeight, \"ft\", 0],\n    [\"Chase volume total with slug\", results.chaseWithSlug, \"bbl\", 0],\n    [\"PPG equivalent at anchor point\", results.slugPpgEquivalent, \"ppge\", 2],\n    [\"PSI equivalent at anchor point\", results.slugPsiEquivalent, \"psi\", 0],\n    [\"APL PSI value for initial flow rate\", results.slugApl, \"psi\", 0],\n    [\"Corrected pill volume for slug\", results.correctedSlugPill, \"bbl\", 0],\n  ]\n    .map((row) => metricRow(...row))\n    .join(\"\");\n}\n\nfunction procedureValue(value, unit, digits) {\n  if (typeof value === \"string\") return value;\n  if (!isNum(value)) return `<span class=\"pending\">Pending</span>`;\n  return `${numberText(value, digits)}${unit ? ` ${unit}` : \"\"}`;\n}\n\nfunction procedureRows(rows) {\n  return rows\n    .map(\n      ([label, value, unit, digits]) => `\n        <div class=\"procedure-result-row\">\n          <span>${label}</span>\n          <strong>${procedureValue(value, unit, digits)}</strong>\n        </div>\n      `,\n    )\n    .join(\"\");\n}\n\nfunction renderProcedureResults(results) {\n  const withSlug = state.pillMode === \"withSlug\";\n  const atSurface = results.topOfPillWithDp === \"Surface\";\n  const totalAtSpot = withSlug\n    ? results.totalPillVolAtSpotWithSlug\n    : results.totalPillVolAtSpotNoSlug;\n  const esdCasingWithDp = atSurface\n    ? results.esdCasingNoDp\n    : results.balancedEsdCasing;\n  const esdTargetWithDp = atSurface ? n(\"desiredEmw\") : results.anchorPointEsd;\n  const pillHeightWithDp = atSurface\n    ? results.heightPillNoDp\n    : results.minHeightWithDp;\n\n  byId(\"procedureOutcome\").innerHTML = `\n    This procedure will result in\n    <strong>${procedureValue(results.correctedPillVol, \"bbl\", 1)}</strong>\n    of the heavy pill into the annulus and leave the remaining\n    <strong>${procedureValue(results.finalKwm, \"bbl\", 1)}</strong>\n    in the drill string.\n  `;\n  byId(\"placementResults\").innerHTML = procedureRows([\n    [\"Total Pill Volume\", results.totalPillVol, \"bbl\", 1],\n    [\"Total Pill Volume @ Spot Depth\", totalAtSpot, \"bbl\", 1],\n    [\"Top of Pill w/ DP\", results.topOfPillWithDp, \"ft\", 0],\n    [\"Top of Pill w/o DP\", results.topOfPillNoDp, \"ft\", 0],\n  ]);\n  byId(\"withDpResults\").innerHTML = procedureRows([\n    [\"ESD @ Casing Shoe\", esdCasingWithDp, \"ppg\", 2],\n    [\"ESD @ Target\", esdTargetWithDp, \"ppg\", 2],\n    [\"Pill Height w/ DP\", pillHeightWithDp, \"ft\", 0],\n  ]);\n  byId(\"withoutDpResults\").innerHTML = procedureRows([\n    [\"ESD @ Casing Shoe\", results.esdCasingNoDp, \"ppg\", 2],\n    [\"ESD @ Anchor Point\", n(\"desiredEmw\"), \"ppg\", 2],\n    [\"Pill Height w/o DP\", results.heightPillNoDp, \"ft\", 0],\n  ]);\n}\n\nfunction drawSchematicMarker(ctx, marker, labelX) {\n  ctx.save();\n  ctx.strokeStyle = marker.color;\n  ctx.lineWidth = marker.lineWidth ?? 2;\n  ctx.setLineDash(marker.dash ?? []);\n  marker.segments.forEach(([fromX, toX]) => {\n    ctx.beginPath();\n    ctx.moveTo(fromX, marker.y);\n    ctx.lineTo(toX, marker.y);\n    ctx.stroke();\n  });\n  ctx.setLineDash([]);\n  ctx.lineWidth = 1.25;\n  ctx.beginPath();\n  ctx.moveTo(marker.connectorX, marker.y);\n  ctx.lineTo(labelX - 18, marker.y);\n  ctx.lineTo(labelX - 8, marker.labelY);\n  ctx.stroke();\n  ctx.restore();\n\n  ctx.fillStyle = marker.color;\n  ctx.font = '700 13px Inter, \"Segoe UI\", sans-serif';\n  ctx.fillText(marker.label, labelX, marker.labelY - 3);\n  ctx.fillStyle = \"#64748b\";\n  ctx.font = '600 12px Inter, \"Segoe UI\", sans-serif';\n  ctx.fillText(marker.depthText, labelX, marker.labelY + 14);\n}\n\nfunction renderSchematic(results) {\n  const canvas = byId(\"wellboreCanvas\");\n  if (!canvas) return;\n\n  const wrapper = canvas.parentElement;\n  const cssWidth = Math.max(760, Math.round(wrapper?.getBoundingClientRect().width || 760));\n  const cssHeight = Math.max(560, Math.min(700, Math.round(cssWidth * 0.56)));\n  const pixelRatio = Math.max(1, Math.min(window.devicePixelRatio || 1, 2));\n  const renderWidth = Math.round(cssWidth * pixelRatio);\n  const renderHeight = Math.round(cssHeight * pixelRatio);\n  if (canvas.width !== renderWidth || canvas.height !== renderHeight) {\n    canvas.width = renderWidth;\n    canvas.height = renderHeight;\n  }\n  canvas.style.width = `${cssWidth}px`;\n  canvas.style.height = `${cssHeight}px`;\n\n  const ctx = canvas.getContext(\"2d\");\n  if (!ctx) return;\n  ctx.setTransform(pixelRatio, 0, 0, pixelRatio, 0, 0);\n  ctx.clearRect(0, 0, cssWidth, cssHeight);\n  ctx.fillStyle = \"#ffffff\";\n  ctx.fillRect(0, 0, cssWidth, cssHeight);\n  ctx.lineCap = \"round\";\n  ctx.lineJoin = \"round\";\n\n  const withSlug = state.pillMode === \"withSlug\";\n  byId(\"schematicMode\").textContent = modeLabel();\n  byId(\"drillStringLegend\").textContent = withSlug\n    ? \"Slug / KMW in drill string\"\n    : \"KMW in drill string\";\n\n  const spotMd = n(\"spotMd\");\n  const casingMd = n(\"casingMd\");\n  const anchorMd = n(\"anchorMd\");\n  const topWithDp =\n    results.topOfPillWithDp === \"Surface\" ? 0 : results.topOfPillWithDp;\n  const topWithoutDp = Math.max(0, results.topOfPillNoDp);\n  const required = [spotMd, topWithDp, results.topOfPillNoDp, results.topOfPillInsideDp];\n  const ready = spotMd > 0 && required.every(isNum);\n\n  if (!ready) {\n    canvas.setAttribute(\"aria-label\", \"Wellbore schematic pending calculated inputs\");\n    ctx.fillStyle = \"#f8fafc\";\n    ctx.fillRect(20, 20, cssWidth - 40, cssHeight - 40);\n    ctx.strokeStyle = \"#cbd5e1\";\n    ctx.lineWidth = 2;\n    ctx.strokeRect(20, 20, cssWidth - 40, cssHeight - 40);\n    ctx.fillStyle = \"#334155\";\n    ctx.font = '800 18px Inter, \"Segoe UI\", sans-serif';\n    ctx.fillText(\"Schematic pending\", 44, 64);\n    ctx.fillStyle = \"#64748b\";\n    ctx.font = '600 14px Inter, \"Segoe UI\", sans-serif';\n    ctx.fillText(\"Complete the geometry and fluid inputs to calculate pill placement.\", 44, 91);\n    return;\n  }\n\n  const topY = 54;\n  const bottomY = cssHeight - 48;\n  const depthSpan = bottomY - topY;\n  const clampDepth = (depth) => Math.max(0, Math.min(spotMd, depth));\n  const yForDepth = (depth) => topY + (clampDepth(depth) / spotMd) * depthSpan;\n  const wellCenter = Math.max(235, Math.min(cssWidth * 0.31, 340));\n  const outerHalf = Math.max(96, Math.min(116, cssWidth * 0.13));\n  const pipeHalf = 31;\n  const outerLeft = wellCenter - outerHalf;\n  const outerRight = wellCenter + outerHalf;\n  const pipeLeft = wellCenter - pipeHalf;\n  const pipeRight = wellCenter + pipeHalf;\n  const labelX = Math.min(cssWidth - 280, outerRight + 72);\n  const annularTopY = yForDepth(topWithDp);\n  const pipeTopY = yForDepth(results.topOfPillInsideDp);\n  const casingShoeY = isNum(casingMd) ? yForDepth(casingMd) : bottomY;\n\n  ctx.fillStyle = \"#eef4f6\";\n  ctx.fillRect(outerLeft + 4, topY, pipeLeft - outerLeft - 7, depthSpan);\n  ctx.fillRect(pipeRight + 3, topY, outerRight - pipeRight - 7, depthSpan);\n  ctx.fillRect(pipeLeft + 3, topY, pipeRight - pipeLeft - 6, depthSpan);\n\n  ctx.fillStyle = \"#b97850\";\n  ctx.fillRect(outerLeft + 4, annularTopY, pipeLeft - outerLeft - 7, bottomY - annularTopY);\n  ctx.fillRect(pipeRight + 3, annularTopY, outerRight - pipeRight - 7, bottomY - annularTopY);\n\n  ctx.fillStyle = withSlug ? \"#c9933c\" : \"#965044\";\n  ctx.fillRect(pipeLeft + 3, pipeTopY, pipeRight - pipeLeft - 6, bottomY - pipeTopY);\n\n  ctx.strokeStyle = \"#475569\";\n  ctx.lineWidth = 7;\n  ctx.beginPath();\n  ctx.moveTo(outerLeft, topY);\n  ctx.lineTo(outerLeft, casingShoeY);\n  ctx.moveTo(outerRight, topY);\n  ctx.lineTo(outerRight, casingShoeY);\n  ctx.stroke();\n\n  ctx.strokeStyle = \"#111827\";\n  ctx.lineWidth = 3.5;\n  ctx.beginPath();\n  ctx.moveTo(outerLeft, casingShoeY);\n  ctx.lineTo(outerLeft - 10, bottomY);\n  ctx.moveTo(outerRight, casingShoeY);\n  ctx.lineTo(outerRight + 10, bottomY);\n  ctx.stroke();\n\n  ctx.lineWidth = 4.5;\n  ctx.beginPath();\n  ctx.moveTo(pipeLeft, topY);\n  ctx.lineTo(pipeLeft, bottomY);\n  ctx.moveTo(pipeRight, topY);\n  ctx.lineTo(pipeRight, bottomY);\n  ctx.stroke();\n\n  ctx.lineWidth = 3.5;\n  ctx.beginPath();\n  ctx.moveTo(pipeLeft - 9, bottomY);\n  ctx.lineTo(wellCenter, bottomY + 12);\n  ctx.lineTo(pipeRight + 9, bottomY);\n  ctx.stroke();\n\n  ctx.strokeStyle = \"#94a3b8\";\n  ctx.lineWidth = 2;\n  ctx.beginPath();\n  ctx.moveTo(outerLeft - 34, topY);\n  ctx.lineTo(outerRight + 34, topY);\n  ctx.stroke();\n  ctx.fillStyle = \"#64748b\";\n  ctx.font = '700 12px Inter, \"Segoe UI\", sans-serif';\n  ctx.fillText(\"Surface\", 24, topY + 4);\n\n  const markers = [\n    {\n      label: \"Top of Pill w/ DP\",\n      depth: topWithDp,\n      depthText: results.topOfPillWithDp === \"Surface\" ? \"Surface\" : `${numberText(topWithDp, 0)} ft MD`,\n      color: \"#dc2626\",\n      lineWidth: 3,\n      segments: [\n        [outerLeft, pipeLeft],\n        [pipeRight, outerRight],\n      ],\n      connectorX: outerRight,\n    },\n    {\n      label: \"Top of Pill w/o DP\",\n      depth: topWithoutDp,\n      depthText:\n        results.topOfPillNoDp <= 0 ? \"Surface\" : `${numberText(results.topOfPillNoDp, 0)} ft MD`,\n      color: \"#e11d48\",\n      dash: [7, 5],\n      segments: [[outerLeft - 6, outerRight + 6]],\n      connectorX: outerRight + 6,\n    },\n    {\n      label: withSlug ? \"Top of Slug / KMW in DP\" : \"Top of KMW in DP\",\n      depth: results.topOfPillInsideDp,\n      depthText: `${numberText(results.topOfPillInsideDp, 0)} ft MD`,\n      color: withSlug ? \"#a16207\" : \"#965044\",\n      dash: [3, 4],\n      segments: [[pipeLeft, pipeRight]],\n      connectorX: pipeRight,\n    },\n    {\n      label: \"Spot Depth\",\n      depth: spotMd,\n      depthText: `${numberText(spotMd, 0)} ft MD`,\n      color: \"#b91c1c\",\n      lineWidth: 3,\n      segments: [[outerLeft - 8, outerRight + 8]],\n      connectorX: outerRight + 8,\n    },\n  ];\n\n  if (isNum(casingMd) && casingMd >= 0 && casingMd <= spotMd) {\n    markers.push({\n      label: \"Casing Shoe\",\n      depth: casingMd,\n      depthText: `${numberText(casingMd, 0)} ft MD`,\n      color: \"#475569\",\n      segments: [\n        [outerLeft - 8, outerLeft + 8],\n        [outerRight - 8, outerRight + 8],\n      ],\n      connectorX: outerRight + 8,\n    });\n  }\n  if (isNum(anchorMd) && anchorMd >= 0 && anchorMd <= spotMd) {\n    markers.push({\n      label: \"Anchor Point / BOC\",\n      depth: anchorMd,\n      depthText: `${numberText(anchorMd, 0)} ft MD`,\n      color: \"#0f766e\",\n      dash: [2, 4],\n      segments: [[outerLeft - 6, outerRight + 6]],\n      connectorX: outerRight + 6,\n    });\n  }\n\n  markers.forEach((marker) => {\n    marker.y = yForDepth(marker.depth);\n  });\n  const sortedMarkers = [...markers].sort((a, b) => a.y - b.y);\n  const labelGap = 43;\n  let priorLabelY = 28 - labelGap;\n  sortedMarkers.forEach((marker) => {\n    marker.labelY = Math.max(marker.y, priorLabelY + labelGap);\n    priorLabelY = marker.labelY;\n  });\n  const bottomOverflow = sortedMarkers.at(-1).labelY - (cssHeight - 28);\n  if (bottomOverflow > 0) {\n    sortedMarkers.forEach((marker) => {\n      marker.labelY -= bottomOverflow;\n    });\n  }\n  for (let index = sortedMarkers.length - 2; index >= 0; index -= 1) {\n    sortedMarkers[index].labelY = Math.min(\n      sortedMarkers[index].labelY,\n      sortedMarkers[index + 1].labelY - labelGap,\n    );\n  }\n  const topOverflow = 28 - sortedMarkers[0].labelY;\n  if (topOverflow > 0) {\n    sortedMarkers.forEach((marker) => {\n      marker.labelY += topOverflow;\n    });\n  }\n  sortedMarkers.forEach((marker) => drawSchematicMarker(ctx, marker, labelX));\n\n  canvas.setAttribute(\n    \"aria-label\",\n    `Wellbore schematic from surface to ${numberText(spotMd, 0)} feet MD. ${modeLabel()} mode. Top of pill with drill pipe at ${\n      results.topOfPillWithDp === \"Surface\" ? \"surface\" : `${numberText(topWithDp, 0)} feet MD`\n    } and top of pill without drill pipe at ${\n      results.topOfPillNoDp <= 0 ? \"surface\" : `${numberText(results.topOfPillNoDp, 0)} feet MD`\n    }.`,\n  );\n}\n\nfunction renderTripTable(results) {\n  const label = results.selectedTripTable === \"other\" ? \"Other\" : results.selectedTripTable;\n  byId(\"tripTableLabel\").textContent = `Auto: ${label} in`;\n  byId(\"tripSpeedRows\").innerHTML = results.tripPressures\n    .map(({ speed, ppge, swabPressure, dynamicPressure }) => {\n      return `\n        <tr>\n          <td>${speed} ft/hr</td>\n          <td>${fmt(ppge, \"ppge\", 2)}</td>\n          <td>${fmt(swabPressure, \"psi\", 0)}</td>\n          <td>${fmt(dynamicPressure, \"psi\", 0)}</td>\n        </tr>\n      `;\n    })\n    .join(\"\");\n}\n\nfunction makeScheduleRows(results, mode = state.pillMode) {\n  const activeMode = mode === \"withSlug\" ? \"withSlug\" : \"noSlug\";\n  const withSlug = activeMode === \"withSlug\";\n  const resolution = n(\"desiredResolution\");\n  const flow = n(\"initialFlowRate\");\n  const pumpDisp = n(\"pumpDisp\");\n  const currentMw = n(\"currentMw\");\n  const kmw = n(\"kmw\");\n  const odDp = n(\"odDp\");\n  const heavyVolume = nonNegative(\n    withSlug ? results.pillVolAtSpot : results.totalPillVol,\n  );\n  const fullPillAtSpot =\n    !withSlug ||\n    !isNum(results.minHeightWithDp) ||\n    !isNum(n(\"spotMd\")) ||\n    n(\"spotMd\") > results.minHeightWithDp;\n  const normalFinalVolume = nonNegative(\n    withSlug ? results.chaseWithSlug : results.kwmPlusChase,\n  );\n  const correctedFinalVolume = nonNegative(results.correctedSlugPill);\n  const finalVolume =\n    withSlug && !fullPillAtSpot && isNum(correctedFinalVolume)\n      ? correctedFinalVolume\n      : normalFinalVolume;\n  const required = [\n    resolution,\n    flow,\n    pumpDisp,\n    currentMw,\n    kmw,\n    odDp,\n    results.drillStringVolAtSpot,\n    results.totalPillVol,\n    heavyVolume,\n    finalVolume,\n    results.staticStrippingPressure,\n    results.resolutionPressureGain,\n    results.pressureDifferential,\n  ];\n  if (withSlug) {\n    required.push(\n      results.pressureDifferentialSlug,\n      results.slugFallOut,\n      results.slugPsiEquivalent,\n    );\n  }\n  if (\n    required.some((value) => !isNum(value)) ||\n    resolution <= 0 ||\n    pumpDisp <= 0 ||\n    heavyVolume <= 0 ||\n    finalVolume <= 0 ||\n    (withSlug && typeof results.slugFits !== \"boolean\")\n  ) {\n    return {\n      rows: [],\n      cutoff: null,\n      mode: activeMode,\n      heavyVolume,\n      finalVolume,\n    };\n  }\n\n  const noSlugInitialVolume = Math.min(\n    heavyVolume,\n    nonNegative(results.drillStringVolAtSpot),\n  );\n  const slugInitialVolume =\n    results.totalPillVol < results.drillStringVolAtSpot\n      ? heavyVolume\n      : Math.min(resolution, finalVolume);\n  let volume = Math.min(\n    withSlug ? slugInitialVolume : noSlugInitialVolume,\n    finalVolume,\n  );\n  let hiddenSbp = withSlug\n    ? results.pressureDifferentialSlug\n    : results.pressureDifferential;\n  let priorStaticSbp = NaN;\n  const rows = [];\n\n  for (let step = 1; step <= 200; step += 1) {\n    let sbp = \"Open Choke\";\n    if (step === 1 && hiddenSbp > 0) {\n      sbp = hiddenSbp;\n    } else if (!withSlug && step === 2 && odDp > 0 && hiddenSbp > 0) {\n      sbp = results.pressureDifferential;\n    } else if (withSlug && step === 2 && results.slugFits) {\n      hiddenSbp = results.pressureDifferential;\n      if (hiddenSbp > 0) sbp = hiddenSbp;\n    } else if (step > 2 && hiddenSbp > 50) {\n      hiddenSbp =\n        hiddenSbp > results.resolutionPressureGain\n          ? Math.max(hiddenSbp - results.resolutionPressureGain, 50)\n          : 50;\n      sbp = hiddenSbp;\n    } else if (withSlug && step === 2 && hiddenSbp > 50) {\n      hiddenSbp =\n        hiddenSbp > results.resolutionPressureGain\n          ? Math.max(hiddenSbp - results.resolutionPressureGain, 50)\n          : 50;\n      sbp = hiddenSbp;\n    }\n\n    const slugPressureOffset =\n      withSlug && results.slugPsiEquivalent > 0 ? results.slugPsiEquivalent : 0;\n    let staticSbp;\n    if (slugPressureOffset > 0) {\n      if (step === 1) {\n        staticSbp = Math.max(0, results.staticStrippingPressure - slugPressureOffset);\n      } else if (step === 2) {\n        staticSbp = Math.max(\n          0,\n          results.staticStrippingPressure - slugPressureOffset * 2,\n        );\n      } else {\n        staticSbp = Math.max(\n          0,\n          priorStaticSbp - results.resolutionPressureGain - slugPressureOffset,\n        );\n      }\n    } else {\n      staticSbp = Math.max(\n        0,\n        results.staticStrippingPressure - (step - 1) * results.resolutionPressureGain,\n      );\n    }\n    priorStaticSbp = staticSbp;\n\n    rows.push({\n      step,\n      sbp,\n      flow,\n      volume,\n      strokes: safeDiv(volume, pumpDisp),\n      density: volume <= heavyVolume ? kmw : currentMw,\n      staticSbp,\n      activityNotes: \"\",\n    });\n\n    if (volume >= finalVolume - 1e-9) break;\n\n    let nextVolume = volume + resolution;\n    const remainingPill = heavyVolume - volume;\n    if (remainingPill > 0 && remainingPill < resolution) {\n      nextVolume = heavyVolume;\n    }\n    nextVolume = Math.min(nextVolume, finalVolume);\n    if (nextVolume <= volume + 1e-9) break;\n    volume = nextVolume;\n  }\n\n  const last = rows.at(-1);\n  const cutoff = last && last.volume >= finalVolume - 1e-9\n    ? {\n        ...last,\n        step: \"\",\n        activityNotes: \"Excluded: Total strokes repeat\",\n      }\n    : null;\n  return {\n    rows,\n    cutoff,\n    mode: activeMode,\n    heavyVolume,\n    finalVolume,\n    fullPillAtSpot,\n  };\n}\n\nfunction renderSchedule(results) {\n  const generated = makeScheduleRows(results, state.pillMode);\n  scheduleCache = generated.rows;\n  scheduleCutoffRow = generated.cutoff;\n  scheduleMeta = generated;\n  const showCutoff = byId(\"showCutoff\").checked && scheduleCutoffRow;\n  const displayRows = showCutoff ? [...scheduleCache, scheduleCutoffRow] : scheduleCache;\n\n  byId(\"scheduleStaticPressure\").textContent = numberText(\n    results.staticStrippingPressure,\n    0,\n  );\n  byId(\"scheduleMaxDynamic\").textContent = numberText(results.maxDynamicSbp, 0);\n  byId(\"scheduleFinalVolume\").textContent = numberText(generated.finalVolume, 0);\n  byId(\"scheduleFinalStrokes\").textContent = numberText(\n    safeDiv(generated.finalVolume, n(\"pumpDisp\")),\n    0,\n  );\n  byId(\"scheduleMode\").textContent = !scheduleCache.length\n    ? \"Waiting for inputs\"\n    : scheduleCutoffRow\n      ? `${modeLabel(generated.mode)} · ${scheduleCache.length} rows · repeat trimmed`\n      : `${modeLabel(generated.mode)} · ${scheduleCache.length} rows · review resolution`;\n\n  byId(\"scheduleRows\").innerHTML = displayRows\n    .map(\n      (row) => `\n        <tr class=\"${row === scheduleCutoffRow ? \"cutoff-row\" : \"\"}\">\n          <td>${row === scheduleCutoffRow ? \"Cutoff\" : row.step}</td>\n          <td>${isNum(row.sbp) ? numberText(row.sbp, 0) : row.sbp}</td>\n          <td>${numberText(row.flow, 0)}</td>\n          <td>${numberText(row.volume, 0)}</td>\n          <td>${numberText(row.strokes, 0)}</td>\n          <td class=\"density-cell\">${numberText(row.density, 2)}</td>\n          <td>${numberText(row.staticSbp, 0)}</td>\n          <td>${row.activityNotes}</td>\n        </tr>\n      `,\n    )\n    .join(\"\");\n}\nfunction renderCement(results) {\n  const cement = results.cement;\n  const kpis = [\n    [\"Static Pressure\", cement.staticPressure, \"psi\", 0],\n    [\"Required Cement Volume\", cement.requiredCementPillVol, \"bbl\", 0],\n    [\"Total Chase Volume\", cement.totalChase, \"bbl\", 0],\n  ];\n  byId(\"cementGrid\").innerHTML = kpis\n    .map(\n      ([label, value, unit, digits]) => `\n        <article class=\"kpi\">\n          <div class=\"label\">${label}</div>\n          <div class=\"value\">${fmt(value, \"\", digits)}</div>\n          <div class=\"unit-text\">${unit}</div>\n        </article>\n      `,\n    )\n    .join(\"\");\n\n  byId(\"cementMetrics\").innerHTML = [\n    [\"Annular capacity\", cement.annularCapacity, \"bbl/ft\", 4],\n    [\"Open hole capacity\", cement.openHoleCapacity, \"bbl/ft\", 4],\n    [\"Casing string capacity\", cement.casingStringCapacity, \"bbl/ft\", 4],\n    [\"Open hole length TD to BOC\", cement.openHoleToBoc, \"ft\", 0],\n    [\"Open hole length BOC to casing shoe\", cement.bocToShoe, \"ft\", 0],\n    [\"Required pill height\", cement.requiredPillHeight, \"ft\", 0],\n    [\"Total casing string volume\", cement.totalCasingStringVol, \"bbl\", 0],\n    [\"Chase after pumping KWM to TD\", cement.chaseToTd, \"bbl\", 0],\n    [\"Chase to exit casing string\", cement.chaseExitCasing, \"bbl\", 0],\n    [\"Chase from casing exit to BOC\", cement.chaseBocToShoe, \"bbl\", 0],\n    [\"Chase BOC to casing shoe plus pill\", cement.chaseBocShoePlusPill, \"bbl\", 0],\n    [\"Top of pill\", cement.topOfPill, \"ft\", 0],\n  ]\n    .map((row) => metricRow(...row))\n    .join(\"\");\n}\n\nfunction renderWarnings(results) {\n  const warnings = [];\n  const withSlug = state.pillMode === \"withSlug\";\n  const required = [\n    [\"anchorTvd\", \"Anchor point TVD\"],\n    [\"casingTvd\", \"Casing depth TVD\"],\n    [\"spotMd\", \"Spot depth MD\"],\n    [\"openHoleDia\", \"Open hole diameter\"],\n    [\"desiredEmw\", \"Desired EMW\"],\n    [\"currentMw\", \"Current MW\"],\n    [\"kmw\", \"KMW\"],\n    [\"idDp\", \"ID drill pipe\"],\n    [\"odDp\", \"OD drill pipe\"],\n    [\"idCasing\", \"ID casing\"],\n    [\"pumpDisp\", \"Pump displacement\"],\n    [\"desiredResolution\", \"Desired resolution\"],\n    [\"initialFlowRate\", \"Initial flow rate\"],\n    [\"safevisionNoSlug\", \"Safevision AP ECD, no slug\"],\n  ];\n  if (withSlug) {\n    required.push(\n      [\"overbalanceSlug\", \"Over balance pressure for slug\"],\n      [\"safevisionSlug\", \"Safevision AP ECD, with slug\"],\n    );\n  }\n  const missing = required.filter(([key]) => !isNum(n(key))).map(([, label]) => label);\n  if (missing.length) {\n    warnings.push({\n      level: \"error\",\n      text: `Missing required values: ${missing.join(\", \")}.`,\n    });\n  }\n  if (isNum(n(\"kmw\")) && isNum(n(\"currentMw\")) && n(\"kmw\") <= n(\"currentMw\")) {\n    warnings.push({\n      level: \"error\",\n      text: \"KMW must be greater than current MW for the pill height formulas.\",\n    });\n  }\n  if (isNum(results.totalPillVol) && isNum(results.drillStringVolAtSpot) && results.totalPillVol > results.drillStringVolAtSpot * 2) {\n    warnings.push({\n      level: \"\",\n      text: \"Total pill volume is high relative to drill string volume at spot depth.\",\n    });\n  }\n  if (isNum(results.masp) && isNum(results.pressureDifferential) && results.pressureDifferential > results.masp) {\n    warnings.push({\n      level: \"error\",\n      text: \"Calculated pressure differential is above MASP.\",\n    });\n  }\n  if (\n    withSlug &&\n    isNum(results.slugPillVol) &&\n    isNum(results.totalPillVol) &&\n    results.slugPillVol >= results.totalPillVol\n  ) {\n    warnings.push({\n      level: \"error\",\n      text: \"Calculated slug volume leaves no remaining pill volume for the spotting schedule.\",\n    });\n  }\n  if (withSlug && results.slugFits === false && isNum(results.slugFallOut)) {\n    warnings.push({\n      level: \"\",\n      text: `Slug exceeds drill string volume at spot depth; ${numberText(results.slugFallOut, 1)} bbl of fallout compensation is applied.`,\n    });\n  }\n  if (!warnings.length) {\n    warnings.push({ level: \"good\", text: \"Inputs are sufficient for the primary calculations.\" });\n  }\n  byId(\"warnings\").innerHTML = warnings\n    .map((warning) => `<div class=\"warning ${warning.level}\">${warning.text}</div>`)\n    .join(\"\");\n  byId(\"validityPill\").textContent = warnings.some((w) => w.level === \"error\")\n    ? \"Needs review\"\n    : \"Calculated\";\n}\n\nfunction render() {\n  renderModeUi();\n  const results = calc();\n  renderDerivedOutputs(results);\n  renderJobStrip();\n  renderScenarioMetrics(results);\n  renderKpis(results);\n  renderMetrics(results);\n  renderProcedureResults(results);\n  renderSchematic(results);\n  renderTripTable(results);\n  renderSchedule(results);\n  renderCement(results);\n  renderWarnings(results);\n}\n\nfunction reset(values = defaults) {\n  Object.keys(state).forEach((key) => {\n    state[key] = values[key] ?? \"\";\n  });\n  state.date = values.date ?? new Date().toISOString().slice(0, 10);\n  state.sectionType = values.sectionType ?? \"Production\";\n  state.pillMode = values.pillMode === \"withSlug\" ? \"withSlug\" : \"noSlug\";\n  document.querySelectorAll(\"[data-key]\").forEach((control) => {\n    control.value = inputValue(control.dataset.key);\n  });\n  render();\n}\n\nfunction initTabs() {\n  document.querySelectorAll(\".tab\").forEach((tab) => {\n    tab.addEventListener(\"click\", () => {\n      document.querySelectorAll(\".tab\").forEach((item) => item.classList.remove(\"active\"));\n      document\n        .querySelectorAll(\".tab-panel\")\n        .forEach((item) => item.classList.remove(\"active\"));\n      tab.classList.add(\"active\");\n      byId(tab.dataset.tab).classList.add(\"active\");\n      if (tab.dataset.tab === \"schematic\") {\n        requestAnimationFrame(() => renderSchematic(calc()));\n      }\n    });\n  });\n}\n\nfunction initSchematicResize() {\n  window.addEventListener(\"resize\", () => {\n    if (!byId(\"schematic\").classList.contains(\"active\")) return;\n    if (schematicResizeFrame) cancelAnimationFrame(schematicResizeFrame);\n    schematicResizeFrame = requestAnimationFrame(() => renderSchematic(calc()));\n  });\n}\n\nfunction saveScenario() {\n  localStorage.setItem(storageKey, JSON.stringify({ savedAt: new Date().toISOString(), state }));\n  byId(\"saveStatus\").textContent = \"Saved locally\";\n  render();\n}\n\nfunction loadSavedScenario() {\n  const saved = localStorage.getItem(storageKey);\n  if (!saved) {\n    byId(\"saveStatus\").textContent = \"No saved scenario found\";\n    return;\n  }\n  const parsed = JSON.parse(saved);\n  reset({ ...defaults, ...(parsed.state || {}) });\n  byId(\"saveStatus\").textContent = \"Loaded saved scenario\";\n}\n\nfunction csvCell(value) {\n  const clean = isNum(value) ? String(round(value, 3)) : String(value ?? \"\");\n  return `\"${clean.replaceAll('\"', '\"\"')}\"`;\n}\n\nfunction exportScheduleCsv() {\n  if (!scheduleCache.length) render();\n  const header = [\n    \"Step\",\n    \"SBP psi\",\n    \"Flow Rate gpm\",\n    \"Volume bbls\",\n    \"Total Strokes stks\",\n    \"Density In ppg\",\n    \"Static SBP psi\",\n    \"Activity Notes\",\n  ];\n  const rows = scheduleCache.map((row) => [\n    row.step,\n    row.sbp,\n    isNum(row.flow) ? round(row.flow, 3) : \"\",\n    isNum(row.volume) ? round(row.volume, 3) : \"\",\n    isNum(row.strokes) ? round(row.strokes, 3) : \"\",\n    isNum(row.density) ? round(row.density, 3) : \"\",\n    isNum(row.staticSbp) ? round(row.staticSbp, 3) : \"\",\n    row.activityNotes,\n  ]);\n  const csv = [header, ...rows].map((row) => row.map(csvCell).join(\",\")).join(\"\\n\");\n  const blob = new Blob([csv], { type: \"text/csv;charset=utf-8\" });\n  const url = URL.createObjectURL(blob);\n  const link = document.createElement(\"a\");\n  const well = (state.wellName || \"mpd-360\").replace(/[^a-z0-9]+/gi, \"-\").replace(/^-|-$/g, \"\").toLowerCase();\n  link.href = url;\n  const mode = scheduleMeta.mode === \"withSlug\" ? \"with-slug\" : \"no-slug\";\n  link.download = `${well || \"mpd-360\"}-${mode}-schedule.csv`;\n  link.click();\n  URL.revokeObjectURL(url);\n}\nfunction initActions() {\n  document.querySelectorAll('input[name=\"pillMode\"]').forEach((control) => {\n    control.addEventListener(\"change\", () => {\n      if (!control.checked) return;\n      state.pillMode = control.value === \"withSlug\" ? \"withSlug\" : \"noSlug\";\n      render();\n    });\n  });\n  byId(\"showCutoff\").addEventListener(\"change\", render);\n  byId(\"loadExample\").addEventListener(\"click\", () => reset({ ...defaults, ...example }));\n  byId(\"saveScenario\").addEventListener(\"click\", saveScenario);\n  byId(\"loadScenario\").addEventListener(\"click\", loadSavedScenario);\n  byId(\"exportSchedule\").addEventListener(\"click\", exportScheduleCsv);\n  byId(\"resetInputs\").addEventListener(\"click\", () => reset(defaults));\n  byId(\"printReport\").addEventListener(\"click\", () => window.print());\n}\n\nbuildInputs();\ninitTabs();\ninitActions();\ninitSchematicResize();\nrender();\n\r\n\r\n\r\n\r\n","contentType":"text/javascript; charset=utf-8","encoding":"text"},"/styles.css":{"body":"﻿:root {\n  color-scheme: light;\n  --ink: #18202a;\n  --muted: #617083;\n  --line: #d8dee7;\n  --panel: #ffffff;\n  --surface: #f4f7fb;\n  --steel: #334155;\n  --teal: #0f766e;\n  --blue: #2563eb;\n  --amber: #b45309;\n  --red: #b91c1c;\n  --green: #15803d;\n  --shadow: 0 18px 45px rgba(28, 41, 57, 0.11);\n}\n\n* {\n  box-sizing: border-box;\n}\n\n[hidden] {\n  display: none !important;\n}\n\nbody {\n  margin: 0;\n  min-width: 320px;\n  background: var(--surface);\n  color: var(--ink);\n  font-family:\n    Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\",\n    sans-serif;\n}\n\nbutton,\ninput,\nselect {\n  font: inherit;\n}\n\n.app-header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 20px;\n  padding: 18px 24px;\n  background: #111827;\n  color: #ffffff;\n}\n\n.eyebrow {\n  margin: 0 0 2px;\n  color: #9ad7cf;\n  font-size: 0.75rem;\n  font-weight: 700;\n  letter-spacing: 0;\n  text-transform: uppercase;\n}\n\nh1,\nh2,\nh3,\np {\n  margin: 0;\n}\n\nh1 {\n  font-size: clamp(1.35rem, 2.5vw, 2.1rem);\n  line-height: 1.1;\n}\n\nh2 {\n  font-size: 1rem;\n}\n\n.header-actions {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  justify-content: flex-end;\n}\n\n.primary-button,\n.ghost-button {\n  min-height: 38px;\n  border: 1px solid rgba(255, 255, 255, 0.3);\n  border-radius: 7px;\n  padding: 8px 14px;\n  cursor: pointer;\n  font-weight: 700;\n}\n\n.primary-button {\n  background: #14b8a6;\n  border-color: #14b8a6;\n  color: #082f2a;\n}\n\n.ghost-button {\n  background: transparent;\n  color: #ffffff;\n}\n\n.app-shell {\n  display: grid;\n  grid-template-columns: minmax(320px, 420px) minmax(0, 1fr);\n  gap: 18px;\n  padding: 18px;\n}\n\n.input-panel,\n.data-section,\n.kpi,\n.tabs {\n  background: var(--panel);\n  border: 1px solid var(--line);\n  box-shadow: var(--shadow);\n}\n\n.input-panel {\n  position: sticky;\n  top: 18px;\n  max-height: calc(100vh - 36px);\n  overflow: auto;\n  border-radius: 8px;\n}\n\n.panel-title,\n.section-heading {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n}\n\n.panel-title {\n  position: sticky;\n  top: 0;\n  z-index: 2;\n  padding: 16px;\n  background: #ffffff;\n  border-bottom: 1px solid var(--line);\n}\n\n#validityPill,\n#scheduleMode {\n  border-radius: 999px;\n  padding: 5px 10px;\n  background: #e0f2fe;\n  color: #075985;\n  font-size: 0.78rem;\n  font-weight: 800;\n  white-space: nowrap;\n}\n\n.input-section {\n  padding: 14px 16px 16px;\n  border-bottom: 1px solid var(--line);\n}\n\n.input-section:last-child {\n  border-bottom: 0;\n}\n\n.input-section h3 {\n  margin-bottom: 12px;\n  color: var(--steel);\n  font-size: 0.82rem;\n  letter-spacing: 0;\n  text-transform: uppercase;\n}\n\n.field-grid {\n  display: grid;\n  grid-template-columns: 1fr;\n  gap: 10px;\n}\n\n.field label {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 10px;\n  margin-bottom: 4px;\n  color: var(--muted);\n  font-size: 0.78rem;\n  font-weight: 700;\n}\n\n.unit {\n  color: #7c8796;\n  font-weight: 600;\n}\n\n.field input,\n.field select {\n  width: 100%;\n  min-height: 38px;\n  border: 1px solid #cbd5e1;\n  border-radius: 6px;\n  background: #ffffff;\n  color: var(--ink);\n  padding: 8px 10px;\n}\n\n.field-output {\n  display: flex;\n  align-items: center;\n  width: 100%;\n  min-height: 38px;\n  border: 1px solid #f0b429;\n  border-radius: 6px;\n  background: #fff8d8;\n  color: #4a3600;\n  padding: 8px 10px;\n  font-variant-numeric: tabular-nums;\n  font-weight: 850;\n}\n\n.section-badge {\n  border-radius: 999px;\n  background: #ecfdf5;\n  color: #166534;\n  padding: 5px 10px;\n  font-size: 0.78rem;\n  font-weight: 800;\n  white-space: nowrap;\n}\n\n.field input:focus,\n.field select:focus {\n  border-color: var(--blue);\n  outline: 3px solid rgba(37, 99, 235, 0.16);\n}\n\n.workspace {\n  min-width: 0;\n}\n\n.tabs {\n  display: flex;\n  align-items: center;\n  flex-wrap: wrap;\n  gap: 4px;\n  margin-bottom: 14px;\n  border-radius: 8px;\n  padding: 5px;\n  overflow-x: auto;\n}\n\n.tab {\n  min-height: 38px;\n  border: 0;\n  border-radius: 6px;\n  background: transparent;\n  color: var(--muted);\n  cursor: pointer;\n  font-weight: 800;\n  padding: 8px 14px;\n  white-space: nowrap;\n}\n\n.tab.active {\n  background: #111827;\n  color: #ffffff;\n}\n\n.pill-mode-switch {\n  display: inline-flex;\n  align-items: center;\n  min-height: 38px;\n  margin-left: auto;\n  border: 1px solid #cbd5e1;\n  border-radius: 7px;\n  background: #eef2f7;\n  overflow: hidden;\n}\n\n.mode-switch-label {\n  padding: 0 10px;\n  color: var(--muted);\n  font-size: 0.72rem;\n  font-weight: 800;\n  text-transform: uppercase;\n}\n\n.mode-option {\n  position: relative;\n  cursor: pointer;\n}\n\n.mode-option input {\n  position: absolute;\n  width: 1px;\n  height: 1px;\n  opacity: 0;\n}\n\n.mode-option span {\n  display: flex;\n  align-items: center;\n  min-height: 36px;\n  padding: 7px 12px;\n  color: var(--steel);\n  font-size: 0.78rem;\n  font-weight: 800;\n  white-space: nowrap;\n}\n\n.mode-option input:checked + span {\n  background: var(--teal);\n  color: #ffffff;\n}\n\n.mode-option input:focus-visible + span {\n  outline: 3px solid rgba(37, 99, 235, 0.24);\n  outline-offset: -3px;\n}\n\n.tab-panel {\n  display: none;\n}\n\n.tab-panel.active {\n  display: block;\n}\n\n.job-strip {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(120px, 1fr));\n  gap: 1px;\n  margin-bottom: 14px;\n  overflow: hidden;\n  border: 1px solid var(--line);\n  border-radius: 8px;\n  background: var(--line);\n  box-shadow: var(--shadow);\n}\n\n.job-strip div {\n  min-height: 74px;\n  background: #ffffff;\n  padding: 13px 14px;\n}\n\n.job-strip span,\n#saveStatus {\n  display: block;\n  color: var(--muted);\n  font-size: 0.75rem;\n  font-weight: 800;\n  text-transform: uppercase;\n}\n\n.job-strip strong {\n  display: block;\n  margin-top: 8px;\n  overflow-wrap: anywhere;\n  color: var(--ink);\n  font-size: 1rem;\n}\n\n.pressure-summary {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(150px, 1fr));\n  gap: 1px;\n  margin-bottom: 14px;\n  overflow: hidden;\n  border: 1px solid #d7b32a;\n  border-radius: 8px;\n  background: #d7b32a;\n  box-shadow: var(--shadow);\n}\n\n.pressure-summary div {\n  min-height: 92px;\n  background: #fffdf3;\n  padding: 13px 14px;\n}\n\n.pressure-summary div:nth-child(-n + 2) {\n  background: #fff3b0;\n}\n\n.pressure-summary span,\n.pressure-summary small {\n  display: block;\n  color: #67540d;\n  font-size: 0.72rem;\n  font-weight: 800;\n  text-transform: uppercase;\n}\n\n.pressure-summary strong {\n  display: inline-block;\n  margin-top: 8px;\n  color: #241d00;\n  font-size: 1.45rem;\n  font-variant-numeric: tabular-nums;\n}\n\n.pressure-summary small {\n  display: inline-block;\n  margin-left: 5px;\n}\n.kpi-grid {\n  display: grid;\n  grid-template-columns: repeat(4, minmax(140px, 1fr));\n  gap: 12px;\n  margin-bottom: 14px;\n}\n\n.kpi-grid.compact {\n  grid-template-columns: repeat(3, minmax(160px, 1fr));\n}\n\n.kpi {\n  min-height: 116px;\n  border-radius: 8px;\n  padding: 14px;\n}\n\n.kpi .label {\n  color: var(--muted);\n  font-size: 0.77rem;\n  font-weight: 800;\n  text-transform: uppercase;\n}\n\n.kpi .value {\n  margin-top: 12px;\n  font-size: 1.85rem;\n  font-weight: 850;\n  line-height: 1;\n}\n\n.kpi .unit-text {\n  margin-top: 6px;\n  color: var(--muted);\n  font-size: 0.82rem;\n  font-weight: 700;\n}\n\n.split-layout {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 14px;\n  margin-bottom: 14px;\n}\n\n.split-layout.single-mode {\n  grid-template-columns: 1fr;\n}\n\n.data-section {\n  border-radius: 8px;\n  margin-bottom: 14px;\n  overflow: hidden;\n}\n\n.section-heading {\n  min-height: 54px;\n  padding: 13px 16px;\n  border-bottom: 1px solid var(--line);\n}\n\n.schedule-controls {\n  display: flex;\n  align-items: center;\n  justify-content: flex-end;\n  gap: 10px;\n}\n\n.toggle-control {\n  display: inline-flex;\n  align-items: center;\n  gap: 7px;\n  color: var(--steel);\n  cursor: pointer;\n  font-size: 0.78rem;\n  font-weight: 750;\n  white-space: nowrap;\n}\n\n.toggle-control input {\n  width: 16px;\n  height: 16px;\n  accent-color: var(--red);\n}\n\n.metric-list {\n  display: grid;\n  grid-template-columns: 1fr;\n}\n\n.metric-row {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  gap: 12px;\n  padding: 10px 16px;\n  border-bottom: 1px solid #eef2f7;\n}\n\n.metric-row:last-child {\n  border-bottom: 0;\n}\n\n.metric-name {\n  color: var(--steel);\n  font-weight: 650;\n}\n\n.metric-value {\n  color: var(--ink);\n  font-variant-numeric: tabular-nums;\n  font-weight: 850;\n  text-align: right;\n  white-space: nowrap;\n}\n\n.procedure-results-body {\n  padding: 16px;\n}\n\n.procedure-outcome {\n  color: var(--steel);\n  font-weight: 700;\n  line-height: 1.6;\n}\n\n.procedure-outcome strong {\n  color: var(--red);\n  font-variant-numeric: tabular-nums;\n  white-space: nowrap;\n}\n\n.procedure-result-grid {\n  display: grid;\n  grid-template-columns: 1.15fr 1fr 1fr;\n  margin-top: 14px;\n  border: 1px solid #aeb7c4;\n}\n\n.procedure-result-group + .procedure-result-group {\n  border-left: 1px solid #aeb7c4;\n}\n\n.procedure-result-group h3 {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  min-height: 42px;\n  padding: 8px 12px;\n  border-bottom: 1px solid #aeb7c4;\n  background: #e5e7eb;\n  color: var(--ink);\n  font-size: 0.8rem;\n  text-align: center;\n}\n\n.procedure-result-row {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) auto;\n  gap: 12px;\n  min-height: 42px;\n  align-items: center;\n  padding: 9px 12px;\n  border-bottom: 1px solid #e3e8ef;\n  color: var(--steel);\n  font-size: 0.82rem;\n  font-weight: 650;\n}\n\n.procedure-result-row:last-child {\n  border-bottom: 0;\n}\n\n.procedure-result-row strong {\n  color: var(--ink);\n  font-variant-numeric: tabular-nums;\n  font-weight: 850;\n  text-align: right;\n  white-space: nowrap;\n}\n\n.schematic-body {\n  padding: 14px 16px 16px;\n}\n\n.schematic-legend {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px 22px;\n  margin-bottom: 12px;\n  color: var(--steel);\n  font-size: 0.8rem;\n  font-weight: 700;\n}\n\n.schematic-legend > span {\n  display: inline-flex;\n  align-items: center;\n  gap: 7px;\n}\n\n.legend-swatch {\n  display: inline-block;\n  width: 14px;\n  height: 14px;\n  border: 1px solid rgba(15, 23, 42, 0.28);\n}\n\n.legend-swatch.annular-pill {\n  background: #b97850;\n}\n\n.legend-swatch.pipe-pill {\n  background: #965044;\n}\n\nbody[data-pill-mode=\"withSlug\"] .legend-swatch.pipe-pill {\n  background: #c9933c;\n}\n\n.legend-line {\n  display: inline-block;\n  width: 22px;\n  border-top: 3px solid #dc2626;\n}\n\n.legend-line.dashed {\n  border-top-style: dashed;\n  border-top-width: 2px;\n}\n\n.schematic-canvas-wrap {\n  width: 100%;\n  overflow-x: auto;\n  border: 1px solid var(--line);\n  background: #ffffff;\n}\n\n.schematic-canvas {\n  display: block;\n  width: 100%;\n  min-width: 760px;\n  background: #ffffff;\n}\n\n.pending {\n  color: #94a3b8;\n}\n\n.table-wrap {\n  width: 100%;\n  overflow: auto;\n}\n\ntable {\n  width: 100%;\n  border-collapse: collapse;\n  min-width: 720px;\n}\n\nth,\ntd {\n  border-bottom: 1px solid #edf1f6;\n  padding: 10px 12px;\n  text-align: left;\n  vertical-align: middle;\n}\n\n.schedule-table {\n  min-width: 880px;\n  table-layout: fixed;\n}\n\n.schedule-table th,\n.schedule-table td {\n  border: 1px solid #20252b;\n  padding: 7px 8px;\n  text-align: center;\n}\n\n.schedule-table th {\n  background: #a7a7a7;\n  color: #0f1115;\n  line-height: 1.15;\n}\n\n.schedule-table th:nth-child(1) {\n  width: 7%;\n}\n\n.schedule-table th:nth-child(2),\n.schedule-table th:nth-child(3),\n.schedule-table th:nth-child(4),\n.schedule-table th:nth-child(5),\n.schedule-table th:nth-child(6),\n.schedule-table th:nth-child(7) {\n  width: 11%;\n}\n\n.schedule-table th:last-child,\n.schedule-table td:last-child {\n  width: 27%;\n  text-align: left;\n}\n\n.schedule-table .density-cell {\n  background: #fff6cf;\n}\n\n.schedule-table .cutoff-row td {\n  background: #fee2e2;\n  color: #7f1d1d;\n  font-weight: 800;\n}\n\n.schedule-table .cutoff-row td:first-child {\n  background-color: #dc2626;\n  background-image: repeating-linear-gradient(\n    -45deg,\n    rgba(255, 255, 255, 0.75) 0,\n    rgba(255, 255, 255, 0.75) 2px,\n    transparent 2px,\n    transparent 5px\n  );\n  color: #111827;\n}\n\nth {\n  background: #f8fafc;\n  color: var(--muted);\n  font-size: 0.76rem;\n  text-transform: uppercase;\n}\n\ntd {\n  font-variant-numeric: tabular-nums;\n}\n\n.warnings {\n  display: grid;\n  gap: 10px;\n  padding: 16px;\n}\n\n.warning {\n  border-left: 4px solid var(--amber);\n  background: #fffbeb;\n  padding: 10px 12px;\n  color: #713f12;\n  font-weight: 700;\n}\n\n.warning.error {\n  border-left-color: var(--red);\n  background: #fef2f2;\n  color: #7f1d1d;\n}\n\n.warning.good {\n  border-left-color: var(--green);\n  background: #f0fdf4;\n  color: #14532d;\n}\n\n.note {\n  padding: 16px;\n  color: var(--muted);\n  line-height: 1.6;\n}\n\n@media (max-width: 1100px) {\n  .app-shell,\n  .split-layout {\n    grid-template-columns: 1fr;\n  }\n\n  .input-panel {\n    position: static;\n    max-height: none;\n  }\n\n  .job-strip,\n  .pressure-summary,\n  .kpi-grid,\n  .kpi-grid.compact {\n    grid-template-columns: repeat(2, minmax(140px, 1fr));\n  }\n\n  .procedure-result-grid {\n    grid-template-columns: 1fr;\n  }\n\n  .procedure-result-group + .procedure-result-group {\n    border-top: 1px solid #aeb7c4;\n    border-left: 0;\n  }\n}\n\n@media (max-width: 640px) {\n  .app-header {\n    align-items: flex-start;\n    flex-direction: column;\n    padding: 16px;\n  }\n\n  .header-actions {\n    width: 100%;\n  }\n\n  .primary-button,\n  .ghost-button {\n    flex: 1 1 92px;\n  }\n\n  .app-shell {\n    padding: 10px;\n  }\n\n  .pill-mode-switch {\n    width: 100%;\n    margin-left: 0;\n  }\n\n  .mode-option {\n    flex: 1;\n  }\n\n  .mode-option span {\n    justify-content: center;\n  }\n\n  .kpi-grid,\n  .kpi-grid.compact,\n  .pressure-summary {\n    grid-template-columns: 1fr;\n  }\n\n  .section-heading,\n  .schedule-controls {\n    align-items: flex-start;\n    flex-direction: column;\n  }\n\n  .metric-row {\n    grid-template-columns: 1fr;\n  }\n\n  .metric-value {\n    text-align: left;\n  }\n\n  .procedure-results-body {\n    padding: 12px;\n  }\n\n  .schematic-body {\n    padding: 12px;\n  }\n\n  .procedure-result-row {\n    grid-template-columns: 1fr;\n    gap: 4px;\n  }\n\n  .procedure-result-row strong {\n    text-align: left;\n  }\n}\n\n@media print {\n  body {\n    background: #ffffff;\n  }\n\n  .input-panel,\n  .tabs,\n  .header-actions,\n  .job-strip,\n  .pill-mode-switch {\n    display: none;\n  }\n\n  .app-shell {\n    display: block;\n    padding: 0;\n  }\n\n  .app-header,\n  .data-section,\n  .kpi {\n    box-shadow: none;\n  }\n\n  .tab-panel {\n    display: block;\n    page-break-after: always;\n  }\n\n  .schematic-canvas {\n    width: 100% !important;\n    min-width: 0;\n    height: auto !important;\n  }\n}\n\r\n\r\n","contentType":"text/css; charset=utf-8","encoding":"text"},"/og.png":{"body":"","contentType":"image/png","encoding":"base64"}};

function decodeBase64(value) {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index);
  }
  return bytes;
}

function responseHeaders(asset, path) {
  const headers = new Headers({
    "Content-Type": asset.contentType,
    "X-Content-Type-Options": "nosniff",
    "Referrer-Policy": "strict-origin-when-cross-origin",
    "Permissions-Policy": "camera=(), microphone=(), geolocation=()",
  });
  if (path === "/index.html") {
    headers.set("Cache-Control", "no-cache");
    headers.set(
      "Content-Security-Policy",
      "default-src 'self'; script-src 'self'; style-src 'self'; img-src 'self' data:; connect-src 'self'; base-uri 'none'; frame-ancestors 'self'; form-action 'self'",
    );
  } else {
    headers.set("Cache-Control", "public, max-age=3600");
  }
  return headers;
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname === "/" ? "/index.html" : url.pathname;
    const asset = assets[path];
    if (!asset) {
      return new Response("Not found", {
        status: 404,
        headers: { "Content-Type": "text/plain; charset=utf-8" },
      });
    }
    const body = request.method === "HEAD"
      ? null
      : asset.encoding === "base64"
        ? decodeBase64(asset.body)
        : asset.body;
    return new Response(body, {
      status: 200,
      headers: responseHeaders(asset, path),
    });
  },
};
